// ================================================================
//  v7.19: 统一禁用/启用控制架构
//  - 设备未连接 → 全局禁用，所有控件灰色不可操作
//  - 设备已连接 → 根据 function.json 决定哪些控件可用
//  - 手动模式 → 白平衡/曝光下拉禁用
// ================================================================

// 控件ID分组（按功能模块）
var CONTROL_GROUPS = {
    // 画面控制
    image: ['consoleBrightness', 'consoleContrast', 'consoleSaturation', 'consoleSharpness',
            'wbMode', 'wbRed', 'wbBlue', 'dnrSpatial', 'dnrTemporal',
            'exposureMode', 'shutterSpeed', 'irisLevel', 'gainLevel',
            'infoOsdSwitch', 'ptzOsdSwitch'],
    // 媒体操作
    media: ['btnConsoleSnapshot', 'btnConsoleRecordStart', 'btnConsoleRecordStop',
            'btnLiveStackStart', 'btnLiveStackStop', 'btnLiveStackSave', 'streamType'],
    // 跟踪控制
    track: ['btnTrackSidereal', 'btnTrackLunar', 'btnTrackSolar', 'btnTrackOff'],
    // 高级功能
    advanced: ['btnConnectFuncRun', 'btnConnectLimitRun', 'btnConnectSpeedRun', 'btnStartDetection']
};

// 手动模式下禁用的控件（曝光相关）
var MANUAL_MODE_DISABLED = ['wbMode', 'wbRed', 'wbBlue', 'shutterSpeed', 'irisLevel'];

/**
 * 统一设置控件启用/禁用状态
 * @param {boolean} enabled - true=启用, false=禁用
 * @param {string} reason - 禁用原因（可选）
 * @param {object} options - 可选配置
 *   - manualMode: boolean - 是否手动模式（手动模式下禁用白平衡/曝光）
 *   - functionData: object - function.json 数据（用于判断端点支持）
 */
function setControlsEnabled(enabled, reason, options) {
    options = options || {};
    var funcData = options.functionData || window.deviceFunctionData;
    var manualMode = options.manualMode || false;

    // 设置单个控件状态
    function _setElement(el, enable) {
        if (!el) return;
        el.disabled = !enable;
        el.style.opacity = enable ? '1' : '0.5';
        el.style.cursor = enable ? 'pointer' : 'not-allowed';
    }

    // 批量设置控件组
    function _setGroup(groupName, enable) {
        var ids = CONTROL_GROUPS[groupName] || [];
        ids.forEach(function(id) {
            _setElement(document.getElementById(id), enable);
        });
    }

    // 设置 PTZ 控制按钮
    function _setPTZButtons(enable) {
        var ptzSection = document.getElementById('ptzControlSection');
        if (ptzSection) {
            var btns = ptzSection.querySelectorAll('.btn, .ptz-btn');
            btns.forEach(function(btn) {
                if (btn.id !== 'ptzSpeed') {  // 速度滑块保持可用
                    _setElement(btn, enable);
                }
            });
        }
    }

    // 主控台提示框
    var consoleWarning = document.getElementById('consoleWarning');
    if (consoleWarning) {
        consoleWarning.style.display = enabled ? 'none' : 'block';
        if (!enabled && reason) {
            var reasonEl = consoleWarning.querySelector('span');
            if (reasonEl) reasonEl.textContent = reason;
        }
    }

    if (!enabled) {
        // === 全局禁用 ===
        _setGroup('image', false);
        _setGroup('media', false);
        _setGroup('track', false);
        _setGroup('advanced', false);
        _setPTZButtons(false);

        // 停止 PTZ 坐标刷新
        if (window.stopPtzImagePoll) window.stopPtzImagePoll();

        console.log('[v7.19] 全局禁用控件:', reason || '设备未连接');
    } else {
        // === 启用（根据功能支持决定） ===

        // 1. PTZ 控制：默认启用（核心功能）
        _setPTZButtons(true);

        // 2. 媒体操作：默认启用
        _setGroup('media', true);

        // 3. 跟踪控制：默认启用
        _setGroup('track', true);

        // 4. 高级功能：默认启用
        _setGroup('advanced', true);

        // 5. 画面控制：根据 function.json 判断
        if (funcData && funcData.function_detection) {
            var fd = funcData.function_detection;

            // 启用所有画面控制
            _setGroup('image', true);

            // 手动模式下禁用白平衡和曝光相关
            if (manualMode) {
                MANUAL_MODE_DISABLED.forEach(function(id) {
                    _setElement(document.getElementById(id), false);
                });
            }

            // 根据端点支持情况微调
            if (fd.gain && fd.gain.supported === false) {
                _setElement(document.getElementById('gainLevel'), false);
            }
            if (fd.iris && fd.iris.supported === false) {
                _setElement(document.getElementById('irisLevel'), false);
            }
            if (fd.shutter && fd.shutter.supported === false) {
                _setElement(document.getElementById('shutterSpeed'), false);
            }
        } else {
            // 无 function.json，禁用画面控制
            _setGroup('image', false);
            console.warn('[v7.19] 无 function.json，禁用画面控制');
        }

        // 启动 PTZ 坐标刷新
        if (window.startPtzImagePoll) window.startPtzImagePoll();

        console.log('[v7.19] 启用控件');
    }
}

// 兼容旧接口（内部调用统一方法）
function disableImageControls(reason) {
    setControlsEnabled(false, reason);
}

function enableImageControls() {
    // v7.19: 检查设备连接状态
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.warn('[v7.19] enableImageControls: 无连接设备，跳过启用');
        return;
    }

    // 获取当前曝光模式
    var exposureMode = document.getElementById('exposureMode');
    var manualMode = exposureMode && exposureMode.value === 'manual';

    setControlsEnabled(true, null, { manualMode: manualMode });
}

// 暴露到全局
window.setControlsEnabled = setControlsEnabled;

