    advanced: ['btnConnectFuncRun', 'btnConnectLimitRun', 'btnConnectSpeedRun', 'btnStartDetection']
};

// 手动模式下才可用的控件（曝光相关）- 自动模式时禁用
var MANUAL_MODE_ONLY = ['shutterSpeed', 'irisLevel', 'gainLevel'];

/**
 * 统一设置控件启用/禁用状态
 * @param {boolean} enabled - true=启用, false=禁用
 * @param {string} reason - 禁用原因（可选）
 * @param {object} options - 可选配置
 *   - manualMode: boolean - 是否手动模式（手动模式下禁用白平衡/曝光）
 *   - functionData: object - function.json 数据（用于判断端点支持）
 */
function setControlsEnabled(enabled, reason, options) {
    options = options || {};
    var funcData = options.functionData || window.deviceFunctionData;
    var manualMode = options.manualMode || false;
    
    // 设置单个控件状态
    function _setElement(el, enable) {
        if (!el) return;
        el.disabled = !enable;
        el.style.opacity = enable ? '1' : '0.5';
        el.style.cursor = enable ? 'pointer' : 'not-allowed';
    }
    
    // 批量设置控件组
    function _setGroup(groupName, enable) {
        var ids = CONTROL_GROUPS[groupName] || [];
        ids.forEach(function(id) {
            _setElement(document.getElementById(id), enable);
        });
    }
    
    // 设置 PTZ 控制按钮
    function _setPTZButtons(enable) {
        var ptzSection = document.getElementById('ptzControlSection');
        if (ptzSection) {
            var btns = ptzSection.querySelectorAll('.btn, .ptz-btn');
            btns.forEach(function(btn) {
                if (btn.id !== 'ptzSpeed') {  // 速度滑块保持可用
                    _setElement(btn, enable);
                }
            });
        }
