    var consoleWarning = document.getElementById('consoleWarning');
    if (consoleWarning) {
        consoleWarning.style.display = enabled ? 'none' : 'block';
        if (!enabled && reason) {
            var reasonEl = consoleWarning.querySelector('span');
            if (reasonEl) reasonEl.textContent = reason;
        }
