function clickLogin2() {
    console.log('[CLICKLOGIN2] Called');
    if (typeof ptzLog === 'function') ptzLog('WASM SDK 登录开始...', 'debug');

    // v6.43: 检查是否已播放成功,避免重复设置 connecting
    if (g_bPlaying2) {
        console.log('[CLICKLOGIN2] Already playing, skip');
        return;
    }

    // 更新 WASM 状态为连接中
    if (window.updateWasmStatus) window.updateWasmStatus('connecting');

    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.log('[WASM SDK] No device connected');
        if (typeof ptzLog === 'function') ptzLog('未连接设备,无法登录', 'warning');
        if (window.updateWasmStatus) window.updateWasmStatus('disconnected');
        return;
    }
    console.log('[CLICKLOGIN2] Device IP: ' + window.connectedDevice.ip);
    if (typeof ptzLog === 'function') ptzLog('连接设备: ' + window.connectedDevice.ip, 'info');
    var szIP = window.connectedDevice.ip;
    var szPort = window.connectedDevice.port || 80;
    var szUsername = window.connectedDevice.username || 'admin';
    var szPassword = window.connectedDevice.password || '';
    g_szDeviceIdentify2 = szIP + '_' + szPort;
    console.log('[WASM SDK] Login: ' + szIP + ':' + szPort);

    // 博客方案:I_Login
    WebVideoCtrl.I_Login(szIP, 1, szPort, szUsername, szPassword, {
        success: function(xmlDoc) {
            g_bLoggedIn2 = true;
            g_szDeviceIdentify2 = szIP + '_' + szPort;
            console.log('[WASM SDK] Login success: ' + g_szDeviceIdentify2);
            if (typeof ptzLog === 'function') ptzLog(szIP + ' 登录成功!', 'success');
            if (window.showToast) window.showToast('success', '设备已连接: ' + szIP);

            // v7.0: 移除灰色覆盖层
            var overlay = document.getElementById('wasm-disconnected-overlay');
            if (overlay) overlay.remove();

            // 更新 WASM 状态为已连接
            if (window.updateWasmStatus) window.updateWasmStatus('connected');

            // 博客方案:延迟500ms后执行 getDevicePort + getChannelInfo
            setTimeout(() => {
                // Step 1: getDevicePort
                var oPort = WebVideoCtrl.I_GetDevicePort(g_szDeviceIdentify2);
                console.log('[WASM SDK] GetDevicePort:', oPort);
                if (oPort) {
                    g_iRtspPort2 = oPort.iRtspPort || 554;
                    g_iWebSocketPort = oPort.iWebSocketPort || 7681;
                    if (typeof ptzLog === 'function') ptzLog('WebSocket端口: ' + g_iWebSocketPort, 'info');
                    document.cookie = 'webVideoCtrlProxyWs=' + szIP + ':' + g_iWebSocketPort + '; path=/';
                    document.cookie = 'webVideoCtrlProxyWsChannel=101; path=/';
                }

                // Step 1.5: 异步获取 token 修复 szAuth(同步XHR被弃用)
                var deviceSet = WebVideoCtrl.w_deviceSet;
                var device = deviceSet && deviceSet.length > 0 ? deviceSet[0] : null;
                var tokenPromise = Promise.resolve();
                if (device && !device.szAuth) {
                    console.log('[WASM SDK] szAuth empty, fetching token async...');
                    tokenPromise = fetch('/ISAPI/Security/token?format=json', {credentials:'include'})
                        .then(function(r) { return r.json(); })
                        .then(function(data) {
                            if (data && data.Token && data.Token.value) {
                                device.szAuth = data.Token.value;
                                console.log('[WASM SDK] szAuth set async:', device.szAuth.substring(0,16) + '...');
                                if (typeof ptzLog === 'function') ptzLog('Token获取成功', 'success');
                            }
                        })
                        .catch(function(e) { console.log('[WASM SDK] Token fetch failed:', e); });
                }

                tokenPromise.then(function() {
                getChannelInfo().then(function() {
                    console.log('[WASM SDK] 获取通道结束');
                    // v7.0: 默认使用第三码流
                    clickStartRealPlay({ iStreamType: 3 });

