// ================================================================
//  v7.22: 统一禁用/启用控制架构（模块内容级别）
//  - 禁用模块内容，保留折叠功能
//  - 折叠标题始终可点击
// ================================================================

// 手动模式下才可用的控件
var MANUAL_MODE_ONLY = ['shutterSpeed', 'irisLevel', 'gainLevel'];

// 设置模块内容状态（保留折叠功能）
function _setModuleContent(sectionId, enable) {
    var section = document.getElementById(sectionId);
    if (!section) return;

    // 只禁用内容区域，保留折叠标题
    var content = section.querySelector('.collapsible-content');
    if (content) {
        content.style.opacity = enable ? '1' : '0.5';
        content.style.pointerEvents = enable ? 'auto' : 'none';
    }
}

// 设置单个控件状态
function _setElement(el, enable) {
    if (!el) return;
    el.disabled = !enable;
    el.style.opacity = enable ? '1' : '0.5';
    el.style.cursor = enable ? 'pointer' : 'not-allowed';
}

// v7.22: 统一设置控件状态
function setControlsEnabled(enabled, reason, options) {
    options = options || {};
    var funcData = options.functionData || window.deviceFunctionData;
    var manualMode = options.manualMode || false;

    if (!enabled) {
        // === 全局禁用 ===
        _setModuleContent('ptzControlSection', false);
        _setModuleContent('trackControlSection', false);
        _setModuleContent('mediaControlSection', false);
        _setModuleContent('imageControlSection', false);

        if (window.stopPtzImagePoll) window.stopPtzImagePoll();
        console.log('[v7.22] 全局禁用:', reason || '设备未连接');
    } else {
        // === 启用 ===
        _setModuleContent('ptzControlSection', true);
        _setModuleContent('trackControlSection', true);
        _setModuleContent('mediaControlSection', true);

        // 画面控制：根据 function.json
        if (funcData && funcData.function_detection) {
            _setModuleContent('imageControlSection', true);
            // 自动模式禁用快门/光圈/增益
            if (!manualMode) {
                MANUAL_MODE_ONLY.forEach(function(id) {
                    _setElement(document.getElementById(id), false);
                });
            }
        } else {
            _setModuleContent('imageControlSection', false);
        }

        if (window.startPtzImagePoll) window.startPtzImagePoll();
        console.log('[v7.22] 启用控件');
    }
}

// 兼容旧接口
function disableImageControls(reason) {
    setControlsEnabled(false, reason);
}

function enableImageControls() {
    if (!window.connectedDevice || !window.connectedDevice.ip) return;
    var exposureMode = document.getElementById('exposureMode');
    var manualMode = exposureMode && exposureMode.value === 'manual';
    setControlsEnabled(true, null, { manualMode: manualMode });
}

// 根据曝光模式更新控件
function updateManualModeControls() {
    var exposureMode = document.getElementById('exposureMode');
    if (!exposureMode) return;
    var isManual = exposureMode.value === 'manual';
    MANUAL_MODE_ONLY.forEach(function(id) {
        _setElement(document.getElementById(id), isManual);
    });
}

function updateShutterIrisState() { updateManualModeControls(); }

window.setControlsEnabled = setControlsEnabled;

