        error: function(status, xmlDoc) {
            console.error('[WASM SDK] 播放失败:', status);
            if (typeof ptzLog === 'function') ptzLog('播放失败: ' + status, 'error');
        }
    });
}

window.clickLogin2 = clickLogin2;
window.getChannelInfo = getChannelInfo;
